### 1. AI重写功能 (AIToolsPanel.tsx)

#### a) 全章重写：
```typescript
// AIToolsPanel.tsx

import React, { useState } from 'react';
import { Button, Modal, Input } from 'antd';

interface RewriteChapterProps {
  aiService: any;
}

const RewriteChapterModal = ({ aiService }: RewriteChapterProps) => {
  const [visible, setVisible] = useState(false);
  const [title, setTitle] = useState('');
  const [summary, setSummary] = useState('');

  const showModal = () => {
    setVisible(true);
  };

  const handleOk = async () => {
    try {
      // 调用 aiService 全章重写 API
      await aiService.rewriteChapter(title, summary);
      alert('全章已成功重写');
      setVisible(false);
    } catch (error) {
      console.error(error.message);
      alert('无法完成重写，请检查输入内容或联系技术支持');
      setVisible(false);
    }
  };

  const handleCancel = () => {
    setVisible(false);
  };

  return (
    <>
      <Button onClick={showModal}>全章重写</Button>
      <Modal
        title="全章重写"
        visible={visible}
        onOk={handleOk}
        onCancel={handleCancel}
      >
        <Input.TextArea placeholder="请输入章节标题" value={title} onChange={(e) => setTitle(e.target.value)} />
        <br/>
        <Input.TextArea placeholder="请输入章节概要" value={summary} onChange={(e) => setSummary(e.target.value)} />
      </Modal>
    </>
  );
};

export default RewriteChapterModal;
```

