#### c) 重写模式选择：
```typescript
// AIToolsPanel.tsx

import React, { useState } from 'react';
import { Button, Modal, Input, Radio } from 'antd';

interface RewritingModeProps {
  aiService: any;
}

const RewritingModes = ({ aiService }: RewritingModeProps) => {
  const [visible, setVisible] = useState(false);
  const [mode, setMode] = useState('简略');
  const [title, setTitle] = useState('');
  const [summary, setSummary] = useState('');

  const showModal = () => {
    setVisible(true);
  };

  const handleOk = async () => {
    try {
      // 根据选择的模式调用相应的 AI 服务
      let prompt: string;

      if (mode === '简略') {
        prompt = `请简化如下章节：\n标题：${title}\n概要：${summary}`;
      } else if (mode === '扩展') {
        prompt = `请扩展如下章节：\n标题：${title}\n概要：${summary}`;
      } else if (mode === '改进') {
        prompt = `请改进如下章节，使其更加引人入胜：\n标题：${title}\n概要：${summary}`;
      }

      await aiService.rewriteWithPrompt(prompt);
      alert('重写成功');
      setVisible(false);
    } catch (error) {
      console.error(error.message);
      alert('无法完成重写，请检查输入内容或联系技术支持');
      setVisible(false);
    }
  };

  const handleCancel = () => {
    setVisible(false);
  };

  return (
    <>
      <Button onClick={showModal}>选择模式</Button>
      <Modal
        title="重写模式"
        visible={visible}
        onOk={handleOk}
        onCancel={handleCancel}
      >
        <Radio.Group onChange={(e) => setMode(e.target.value)} value={mode}>
          <Radio value="简略">简化重写</Radio>
          <Radio value="扩展">扩展重写</Radio>
          <Radio value="改进">改进建议重写</Radio>
        </Radio.Group>
        <br/>
        <Input.TextArea placeholder="请输入章节标题" value={title} onChange={(e) => setTitle(e.target.value)} />
        <br/>
        <Input.TextArea placeholder="请输入章节概要" value={summary} onChange={(e) => setSummary(e.target.value)} />
      </Modal>
    </>
  );
};

export default RewritingModes;
```

